mapper.select:
SELECT IFNULL(AVG(t.actual_work_hours), 0)
FROM eb_attendance_statistics t
WHERE t.deleted_at IS NULL
  AND t.uid = #{uid}
  AND t.created_at >= #{start}
  AND t.created_at <= #{end}

SELECT COUNT(1)
FROM eb_attendance_statistics t
WHERE t.deleted_at IS NULL
  AND t.uid = #{uid}
  AND t.created_at >= #{start}
  AND t.created_at <= #{end}
  AND (
	t.one_shift_status > 0 OR t.two_shift_status > 0 OR t.three_shift_status > 0 OR t.four_shift_status > 0
	)

SELECT COUNT(1)
FROM eb_attendance_statistics t
WHERE t.deleted_at IS NULL
  AND t.uid = #{uid}
  AND t.created_at >= #{start}
  AND t.created_at <= #{end}
  AND (
	t.one_shift_status IN
	#{st}
	OR t.two_shift_status IN
	#{st}
	OR t.three_shift_status IN
	#{st}
	OR t.four_shift_status IN
	#{st}
	)

SELECT t.*
FROM eb_attendance_statistics t
WHERE t.deleted_at IS NULL
  AND t.uid = #{uid}
  AND t.created_at >= #{start}
  AND t.created_at <= #{end}

SELECT t.*
FROM eb_attendance_statistics t
WHERE t.deleted_at IS NULL
  AND t.uid = #{uid}
  AND DATE_FORMAT(t.created_at, '%Y-%m') = #{monthYm}

SELECT t.*
FROM eb_attendance_statistics t

	AND t.deleted_at IS NULL
	AND t.uid = #{uid}

		AND t.created_at >= #{q.rangeStart} AND t.created_at <= #{q.rangeEnd}


		AND DATE_FORMAT(t.created_at, '%Y-%m') = #{q.monthYm}

	AND (


			(
			t.one_shift_status IN
			#{st}
			OR t.two_shift_status IN
			#{st}
			OR t.three_shift_status IN
			#{st}
			OR t.four_shift_status IN
			#{st}
			)
			OR
			(
			t.one_shift_location_status = #{q.repairLocationStatus}
			OR t.two_shift_location_status = #{q.repairLocationStatus}
			OR t.three_shift_location_status = #{q.repairLocationStatus}
			OR t.four_shift_location_status = #{q.repairLocationStatus}
			)


			(
			t.one_shift_status IN
			#{st}
			OR t.two_shift_status IN
			#{st}
			OR t.three_shift_status IN
			#{st}
			OR t.four_shift_status IN
			#{st}
			)


			(
			t.one_shift_location_status = #{q.repairLocationStatus}
			OR t.two_shift_location_status = #{q.repairLocationStatus}
			OR t.three_shift_location_status = #{q.repairLocationStatus}
			OR t.four_shift_location_status = #{q.repairLocationStatus}
			)


			1 = 0


	)

ORDER BY t.id DESC
